from __future__ import annotations
import os
import socket
import requests
from arcgis.auth.tools import LazyLoader

_arcgis_gis = LazyLoader("arcgis.gis")


def get_secret(key: str, gis: _arcgis_gis.GIS | None = None) -> str | None:
    """
    Returns a user defined secret for the notebook server environment.

    ====================    ====================================================================
    **Parameter**           **Description**
    --------------------    --------------------------------------------------------------------
    key                     Required String. The name of the secret to get the value for.
    --------------------    --------------------------------------------------------------------
    gis                     Optional GIS. The `GIS` object to look at for the secret store.
    ====================    ====================================================================

    :return: string or None
    """
    if gis is None:
        from arcgis import env

        gis = env.active_gis
    url: str | None = os.environ.get("NB_CRED_API_URL", None)
    if os.environ.get("NB_CRED_API_URL", None) is None:
        raise Exception(
            "The secret store is not supported on this notebook environment. Please contact your administrator."
        )
    nb_auth_file = os.getenv("NB_AUTH_FILE", None)
    if nb_auth_file is None:
        raise ValueError(
            "Cannot find the NB AUTH file.  Please verify that you are running in a valid Notebook Server environment."
        )
    try:
        from arcgis_notebooks_auth import get_secret as _get_secret
    except:
        raise Exception("The current environment does not support the secret store.")
    jpy_session_name: str = ""
    if os.environ.get("JPY_SESSION_NAME", None):
        jpy_session_name: str = (
            "/" + os.environ["JPY_SESSION_NAME"].split(os.sep)[-1].split(".")[0]
        )
    try:
        original_agent_text: str = gis.session.headers["User-Agent"]
        gis.session.headers["User-Agent"] = (
            f"geosaurus/{socket.gethostname()}{jpy_session_name}"
        )
        resp: requests.Response = gis.session.post(
            url=url, data={"f": "json", "all": "true"}
        )
        data: dict = resp.json()
    except Exception as ex:
        raise Exception(ex)
    finally:
        gis.session.headers["User-Agent"] = original_agent_text
    return _get_secret(nb_auth_file, data, key)
